import{c as e,Q as o,j as t,m as r}from"./chunks/framework.CPTW7DhK.js";const p=JSON.parse('{"title":"Sistemas de TEF Homologados","description":"Sistemas de Transferência Eletrônica de Fundos homologados com os sistemas Desbravador","frontmatter":{"title":"Sistemas de TEF Homologados","description":"Sistemas de Transferência Eletrônica de Fundos homologados com os sistemas Desbravador","audience":"Cliente / Equipe de TI / Fornecedor de hardware","updated":"2026-05-24T00:00:00.000Z"},"headers":[],"relativePath":"perifericos/tef-homologados.md","filePath":"perifericos/tef-homologados.md","lastUpdated":null}'),s={name:"perifericos/tef-homologados.md"};function d(i,a,n,l,c,m){return o(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="sistemas-de-tef-homologados" tabindex="-1">Sistemas de TEF Homologados <a class="header-anchor" href="#sistemas-de-tef-homologados" aria-label="Permalink to &quot;Sistemas de TEF Homologados&quot;">​</a></h1><blockquote><p>ℹ️ Esta é uma página compartilhada entre todos os sistemas Desbravador. Última atualização: 24/05/2026.</p></blockquote><hr><h2 id="o-que-e-tef" tabindex="-1">O que é TEF <a class="header-anchor" href="#o-que-e-tef" aria-label="Permalink to &quot;O que é TEF&quot;">​</a></h2><p>TEF (Transferência Eletrônica de Fundos) é o sistema que permite o processamento integrado de pagamentos com cartão de crédito, débito e demais modalidades eletrônicas diretamente no ERP/PDV. A integração TEF elimina a necessidade de equipamentos autônomos de captura, centralizando a autorização das transações dentro do fluxo de venda do sistema.</p><hr><h2 id="sistemas-homologados" tabindex="-1">Sistemas Homologados <a class="header-anchor" href="#sistemas-homologados" aria-label="Permalink to &quot;Sistemas Homologados&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Sistema</th><th>Fornecedor</th><th>Modelo de integração</th></tr></thead><tbody><tr><td><strong>FiServ</strong></td><td>FiServ (anteriormente First Data / Bin)</td><td>TEF dedicado / discado</td></tr><tr><td><strong>TEF Scope</strong></td><td>Conexão Itaú — Itaú Unibanco</td><td>TEF dedicado via Scope</td></tr></tbody></table><blockquote><p>ℹ️ A contratação dos serviços de TEF é feita diretamente pelo cliente com o adquirente ou banco. A Desbravador realiza a integração técnica — não intermedia a contratação comercial.</p></blockquote><hr><h2 id="fiserv" tabindex="-1">FiServ <a class="header-anchor" href="#fiserv" aria-label="Permalink to &quot;FiServ&quot;">​</a></h2><p>A FiServ é uma empresa global de tecnologia financeira, resultante da fusão entre a First Data e a Fiserv. No Brasil, operou historicamente sob as marcas First Data e Bin, e atualmente consolida seus serviços de captura e processamento de pagamentos sob a marca FiServ.</p><p>A integração com os sistemas Desbravador é realizada via módulo de TEF dedicado, com comunicação entre o PDV e o pinpad homologado instalado na estação de trabalho. A autorização das transações ocorre de forma transparente ao operador, sem necessidade de equipamento autônomo.</p><blockquote><p>⚠️ <strong>Atenção</strong> — Antes de contratar qualquer solução de TEF, confirme a versão homologada com a equipe Desbravador para garantir compatibilidade com o sistema e módulos utilizados.</p></blockquote><hr><h2 id="tef-scope-conexao-itau" tabindex="-1">TEF Scope / Conexão Itaú <a class="header-anchor" href="#tef-scope-conexao-itau" aria-label="Permalink to &quot;TEF Scope / Conexão Itaú&quot;">​</a></h2><p>O TEF Scope é a solução de captura eletrônica de pagamentos oferecida pelo Itaú Unibanco por meio da plataforma Conexão Itaú. Permite o processamento de transações de crédito, débito e outras modalidades com integração direta ao fluxo de venda do ERP/PDV.</p><p>A integração com os sistemas Desbravador utiliza o protocolo Scope, com comunicação entre a aplicação de TEF instalada na estação e o pinpad homologado. A configuração da solução exige habilitação prévia junto ao Itaú Unibanco.</p><blockquote><p>⚠️ <strong>Atenção</strong> — Antes de contratar qualquer solução de TEF, confirme a versão homologada com a equipe Desbravador para garantir compatibilidade com o sistema e módulos utilizados.</p></blockquote><hr><h2 id="requisitos-de-infraestrutura-para-tef" tabindex="-1">Requisitos de Infraestrutura para TEF <a class="header-anchor" href="#requisitos-de-infraestrutura-para-tef" aria-label="Permalink to &quot;Requisitos de Infraestrutura para TEF&quot;">​</a></h2><p>Para que a integração TEF funcione corretamente em qualquer um dos sistemas homologados, os seguintes requisitos devem ser atendidos na estação de trabalho e na infraestrutura de rede:</p><table tabindex="0"><thead><tr><th>Requisito</th><th>Detalhe</th></tr></thead><tbody><tr><td><strong>Conexão com a internet</strong></td><td>Estável e dedicada — oscilações causam falha ou timeout nas transações</td></tr><tr><td><strong>Pinpad homologado</strong></td><td>Instalado e conectado à estação que processa os pagamentos</td></tr><tr><td><strong>Drivers do pinpad</strong></td><td>Instalados, atualizados e compatíveis com o sistema operacional em uso</td></tr><tr><td><strong>Porta de comunicação</strong></td><td>USB ou serial disponível e livre de conflitos</td></tr><tr><td><strong>Aplicação de TEF</strong></td><td>Instalada, configurada e ativa na estação antes do uso</td></tr><tr><td><strong>Firewall</strong></td><td>Portas de comunicação liberadas conforme especificação do adquirente ou processador</td></tr></tbody></table><blockquote><p>⚠️ <strong>Atenção</strong> — A instalação e configuração da aplicação de TEF deve ser realizada por técnico habilitado pelo adquirente. A Desbravador não realiza instalação de software de terceiros.</p></blockquote><p>Para verificar os modelos de pinpad compatíveis com os sistemas de TEF homologados:</p><ul><li>💳 <a href="./pinpads-homologados.html">Pinpads homologados</a></li></ul><hr><h2 id="observacoes-importantes" tabindex="-1">Observações Importantes <a class="header-anchor" href="#observacoes-importantes" aria-label="Permalink to &quot;Observações Importantes&quot;">​</a></h2><ul><li>A homologação de um sistema de TEF é específica por versão de software. Uma atualização do sistema Desbravador ou da aplicação de TEF pode exigir nova validação de compatibilidade.</li><li>Em caso de troca de adquirente ou processador, verificar com a equipe Desbravador se a nova solução é suportada antes de realizar a migração.</li><li>Problemas de comunicação TEF (timeout, falha de conexão, transação não autorizada) devem ser investigados primeiramente junto ao adquirente, que dispõe de ferramentas de diagnóstico de transação.</li><li>O TEF móvel (processamento em mesas ou ambientes externos) pode ter requisitos adicionais de hardware e rede — consultar a Desbravador para orientação específica.</li></ul><hr><h2 id="contato-e-suporte" tabindex="-1">Contato e Suporte <a class="header-anchor" href="#contato-e-suporte" aria-label="Permalink to &quot;Contato e Suporte&quot;">​</a></h2><p><strong>Desbravador Software Ltda.</strong><br> 🌐 <a href="https://www.desbravador.com.br" target="_blank" rel="noreferrer">www.desbravador.com.br</a></p><p>Para dúvidas sobre compatibilidade, versões homologadas ou integração de novos sistemas de TEF, entre em contato com a equipe técnica da Desbravador.</p>',33)])])}const h=e(s,[["render",d]]);export{p as __pageData,h as default};
